#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10,mod=998244353;

struct Node{
    int v,f,g;
    bool operator<(Node x)const{
        if(v!=x.v) return v<x.v;
        if(f!=x.f) return f<x.f;
        return g<x.g;
    }
};

int n,m,q[N],hh=1,tt=0,ans=1;
set<Node> s[N];
bool inq[N];

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        if(u==v)
        	continue;
        if(s[u].find({v,1,1})==s[u].end() && s[u].find({v,2,1})==s[u].end()){
            s[u].insert({v,1,1});
            s[v].insert({u,1,1});
        }else if(s[u].find({v,2,1})==s[u].end()){
            s[u].erase({v,1,1});
            s[v].erase({u,1,1});
            s[u].insert({v,2,1});
            s[v].insert({u,2,1});
        }else{
        	s[u].erase({v,2,1});
            s[v].erase({u,2,1});
            s[u].insert({v,3,1});
            s[v].insert({u,3,1});
		}
    }
    for(int i=1;i<=n;i++)
        if(s[i].size()<=2){
            q[++tt]=i;
            inq[i]=1;
        }
    while(hh<=tt){
        int x=q[hh++];
        if(s[x].size()==0)
            continue;
        if(s[x].size()==1){
            Node tmp=*s[x].begin();
            ans=1ll*ans*tmp.f%mod;
            s[x].clear();
            s[tmp.v].erase({x,tmp.f,tmp.g});
            if(!inq[tmp.v] && s[tmp.v].size()<=2){
            	q[++tt]=tmp.v;
				inq[tmp.v]=1;
			}
        }else{
            auto it=s[x].begin();
            Node a,b,c;
            int u,v;
            a=*it,it++,b=*it;
            u=a.v,v=b.v;
            c.f=1ll*a.f*b.f%mod;
            c.g=(1ll*a.f*b.g+1ll*a.g*b.f)%mod;

            it=s[u].lower_bound({v,0,0});
            if(it!=s[u].end() && (*it).v==v){
                Node d=c,e=*it;
                c.f=(1ll*d.f*e.g+1ll*d.g*e.f)%mod;
                c.g=1ll*d.g*e.g%mod;
                s[u].erase(e);
                s[v].erase({u,e.f,e.g});
            }
            s[x].clear();
            s[u].erase({x,a.f,a.g});
            s[v].erase({x,b.f,b.g});
            s[u].insert({v,c.f,c.g});
            s[v].insert({u,c.f,c.g});
            if(!inq[u] && s[u].size()<=2){
            	q[++tt]=u;
            	inq[u]=1;
			}
			if(!inq[v] && s[v].size()<=2){
				q[++tt]=v;
				inq[v]=1;
			}
        }
    }
    printf("%d",ans);
    return 0;
}
